INSERT INTO `user_comments` VALUES (1,'Bu tahminleri yapmaya benim kapasitem yetmez. Adem abimden yardim alabilir miyim?','2026-06-11 17:34:06.882005','kubilay'),(2,'Gruplar yaratıp, grup linkini paylaşarak insanları ayrı ayrı gruplara eklemek kullanırlılığı arttırır. Tahminler ortak ama puanlama grup grup ayrı. UI basic duruyor. Ülke bayrakları, background rengi, telde kullanırken yana kayma zorunluluğu olmasa şık olabilir. Toplu giriş aldıklarında toplu save butonu daha mantıklı olabilir','2026-06-13 11:27:39.338604','tcan'),(3,'PP fotolarını değiştirebilelim , ayrıca sayfada 2 maçı girip tek büyük save butonu gelsin teker teker save etme butonu da dursun ama fazladan girilen tahminlerde mutlaka bir çözüm bulunmalı','2026-06-15 06:56:51.661607','sadik');
/*!40000 ALTER TABLE `user_comments` ENABLE KEYS */;
